class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.points = [];
        this.generateData(initialInputs.seed);

        this.colors = {
            bg: '#0f172a',
            classA: '#3b82f6', // Blue
            classB: '#f43f5e', // Rose
            query: '#fbbf24',  // Amber
            text: '#f8fafc',
            faded: '#334155'
        };

        window.addEventListener('resize', () => this.resize());
        this.resize();
    }

    generateData(seed) {
        const seededRandom = (s) => {
            let t = s += 0x6D2B79F5;
            t = Math.imul(t ^ t >>> 15, t | 1);
            t ^= t + Math.imul(t ^ t >>> 7, t | 61);
            return ((t ^ t >>> 14) >>> 0) / 4294967296;
        };

        this.points = [];
        let s = seed;
        // Class A: Cluster 1
        for (let i = 0; i < 20; i++) {
            this.points.push({
                x: 20 + seededRandom(s++) * 40,
                y: 50 + seededRandom(s++) * 40,
                label: 'A'
            });
        }
        // Class B: Cluster 2
        for (let i = 0; i < 20; i++) {
            this.points.push({
                x: 40 + seededRandom(s++) * 40,
                y: 10 + seededRandom(s++) * 40,
                label: 'B'
            });
        }
    }

    resize() {
        this.width = this.container.clientWidth;
        this.height = this.container.clientHeight || 400;
        this.canvas.width = this.width * window.devicePixelRatio;
        this.canvas.height = this.height * window.devicePixelRatio;
        this.canvas.style.width = this.width + 'px';
        this.canvas.style.height = this.height + 'px';
        this.ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    }

    getDist(p1, p2, metric) {
        if (metric === 'Manhattan') {
            return Math.abs(p1.x - p2.x) + Math.abs(p1.y - p2.y);
        }
        return Math.sqrt(Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2));
    }

    getSteps(inputs) {
        if (this.lastSeed !== inputs.seed) {
            this.generateData(inputs.seed);
            this.lastSeed = inputs.seed;
        }

        const query = { x: inputs.qx, y: inputs.qy };
        const distances = this.points.map(p => ({
            ...p,
            dist: this.getDist(p, query, inputs.metric)
        })).sort((a, b) => a.dist - b.dist);

        const neighbors = distances.slice(0, inputs.k_value);
        const countA = neighbors.filter(n => n.label === 'A').length;
        const countB = neighbors.filter(n => n.label === 'B').length;
        const winner = countA > countB ? 'Blue (A)' : countB > countA ? 'Rose (B)' : 'Tie';

        return [
            {
                title: "Step 1: Training Data",
                description: "We start with a set of labeled data points in 2D space. Points are assigned to either **Class A (Blue)** or **Class B (Rose)**."
            },
            {
                title: "Step 2: The Query Point",
                description: `A new, unclassified query point $P$ is placed at $(${inputs.qx}, ${inputs.qy})$. Our goal is to predict its label.`
            },
            {
                title: "Step 3: Calculating Distances",
                description: `Using the **${inputs.metric}** metric, we calculate the distance from $P$ to every other point in the dataset.`
            },
            {
                title: "Step 4: Finding k-Neighbors",
                description: `We select the $k = ${inputs.k_value}$ points with the smallest calculated distances. These are highlighted on the canvas.`
            },
            {
                title: "Step 5: Majority Vote",
                description: `Among the neighbors, **${countA}** belong to Class A and **${countB}** belong to Class B. The majority vote result is: **${winner}**.`
            }
        ];
    }

    toCanvasX(x) {
        const margin = 40;
        return margin + (x / 100) * (this.width - margin * 2);
    }

    toCanvasY(y) {
        const margin = 40;
        return (this.height - margin) - (y / 100) * (this.height - margin * 2);
    }

    render(inputs, stepIndex) {
        const ctx = this.ctx;
        ctx.clearRect(0, 0, this.width, this.height);
        ctx.fillStyle = this.colors.bg;
        ctx.fillRect(0, 0, this.width, this.height);

        const query = { x: inputs.qx, y: inputs.qy };
        const distances = this.points.map(p => ({
            ...p,
            dist: this.getDist(p, query, inputs.metric)
        })).sort((a, b) => a.dist - b.dist);
        const neighbors = distances.slice(0, inputs.k_value);

        // Draw Axes
        ctx.strokeStyle = this.colors.faded;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(this.toCanvasX(0), this.toCanvasY(0));
        ctx.lineTo(this.toCanvasX(100), this.toCanvasY(0));
        ctx.moveTo(this.toCanvasX(0), this.toCanvasY(0));
        ctx.lineTo(this.toCanvasX(0), this.toCanvasY(100));
        ctx.stroke();

        // Draw Training Points
        this.points.forEach(p => {
            ctx.beginPath();
            ctx.arc(this.toCanvasX(p.x), this.toCanvasY(p.y), 5, 0, Math.PI * 2);
            ctx.fillStyle = p.label === 'A' ? this.colors.classA : this.colors.classB;
            ctx.globalAlpha = (stepIndex === 0) ? 1.0 : 0.4;
            ctx.fill();
        });
        ctx.globalAlpha = 1.0;

        // Step 1: Query Point
        if (stepIndex >= 1) {
            ctx.beginPath();
            ctx.arc(this.toCanvasX(query.x), this.toCanvasY(query.y), 8, 0, Math.PI * 2);
            ctx.fillStyle = this.colors.query;
            ctx.shadowBlur = 10;
            ctx.shadowColor = this.colors.query;
            ctx.fill();
            ctx.shadowBlur = 0;
            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 2;
            ctx.stroke();
        }

        // Step 2: Distance lines
        if (stepIndex === 2) {
            ctx.setLineDash([5, 5]);
            ctx.strokeStyle = this.colors.faded;
            this.points.forEach(p => {
                ctx.beginPath();
                ctx.moveTo(this.toCanvasX(query.x), this.toCanvasY(query.y));
                ctx.lineTo(this.toCanvasX(p.x), this.toCanvasY(p.y));
                ctx.stroke();
            });
            ctx.setLineDash([]);
        }

        // Step 3 & 4: Highlight Neighbors
        if (stepIndex >= 3) {
            neighbors.forEach(n => {
                const px = this.toCanvasX(n.x);
                const py = this.toCanvasY(n.y);
                const qx = this.toCanvasX(query.x);
                const qy = this.toCanvasY(query.y);

                // Highlight point
                ctx.beginPath();
                ctx.arc(px, py, 7, 0, Math.PI * 2);
                ctx.fillStyle = n.label === 'A' ? this.colors.classA : this.colors.classB;
                ctx.globalAlpha = 1.0;
                ctx.fill();
                ctx.strokeStyle = '#fff';
                ctx.lineWidth = 2;
                ctx.stroke();

                // Connection line
                ctx.beginPath();
                ctx.setLineDash([]);
                ctx.lineWidth = 1.5;
                ctx.strokeStyle = n.label === 'A' ? this.colors.classA : this.colors.classB;
                ctx.moveTo(qx, qy);
                ctx.lineTo(px, py);
                ctx.stroke();
            });
        }

        // Step 4 Labeling
        if (stepIndex >= 4) {
            const countA = neighbors.filter(n => n.label === 'A').length;
            const countB = neighbors.filter(n => n.label === 'B').length;
            const winnerColor = countA >= countB ? this.colors.classA : this.colors.classB;

            ctx.fillStyle = winnerColor;
            ctx.font = 'bold 16px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText(`Winner: ${countA > countB ? 'Class A' : 'Class B'}`, this.toCanvasX(query.x), this.toCanvasY(query.y) - 20);
        }
    }
}
